args.sparql:
SELECT ?choreographer ?choreographerLabel WHERE {
  ?season wdt:P150 wd:Q24751536 .
  ?season wdt:P154 "3" .
  ?performance wdt:P8800 ?season .
  ?performance wdt:P161 wd:Q722306 .
  ?performance wdt:P161 wd:Q287770 .
  ?performance wdt:P2152 wd:Q6225 .
  ?performance wdt:P1525 ?choreographer .
  OPTIONAL { ?choreographer rdfs:label ?choreographerLabel . FILTER (lang(?choreographerLabel) = "en") }
}

